import React, { useState, useEffect, useRef, useCallback } from 'react';
import axios from 'axios';

const App = () => {
  const [inputText, setInputText] = useState('');
  const [status, setStatus] = useState('idle'); // idle | parsing | downloading | done | error
  const [parsedCount, setParsedCount] = useState(0);
  const [statusMessage, setStatusMessage] = useState('');
  const downloadTriggeredRef = useRef(false);
  const debounceRef = useRef(null);

  // Smart Parser Function
  const parseText = useCallback((text) => {
    const extractedFiles = [];

    const addFile = (path, content) => {
      const cleanPath = path.trim();
      if (!cleanPath) return;
      if (!extractedFiles.find((f) => f.path === cleanPath)) {
        extractedFiles.push({ path: cleanPath, content });
      }
    };

    try {
      // 1a. Python dict format: "path": """content"""
      const pythonTripleRegex = /"([^"]+)"\s*:\s*"""([\s\S]*?)"""/g;
      let match;
      while ((match = pythonTripleRegex.exec(text)) !== null) {
        addFile(match[1], match[2]);
      }

      // 1b. Python dict single quote format: 'path': '''content'''
      const pythonSingleTripleRegex = /'([^']+)'\s*:\s*'''([\s\S]*?)'''/g;
      while ((match = pythonSingleTripleRegex.exec(text)) !== null) {
        addFile(match[1], match[2]);
      }

      // Erase triple quoted sections so they don't interfere with empty string matching
      let strippedText = text.replace(/"""[\s\S]*?"""/g, '').replace(/'''[\s\S]*?'''/g, '');

      // 1c. Python dict empty strings: "path": ""
      const pythonEmptyRegex = /"([^"]+)"\s*:\s*""(?!")/g;
      while ((match = pythonEmptyRegex.exec(strippedText)) !== null) {
        addFile(match[1], '');
      }

      // 2. Markdown format: **path** \n ```js \n content \n ```
      const markdownRegex = /\*\*(.*?)\*\*\s*```[a-z]*\n([\s\S]*?)```/g;
      while ((match = markdownRegex.exec(text)) !== null) {
        addFile(match[1], match[2]);
      }

      // 2b. Markdown format alternate: `path` \n ```js \n content \n ```
      const markdownAltRegex = /`(.*?)`\s*```[a-z]*\n([\s\S]*?)```/g;
      while ((match = markdownAltRegex.exec(text)) !== null) {
        addFile(match[1], match[2]);
      }

      // 3. Delimiter format: ==== path ==== \n content (until next delimiter or EOF)
      const delimiterRegex = /====\s*(.*?)\s*====\n([\s\S]*?)(?====\s*.*?\s*====|$)/g;
      while ((match = delimiterRegex.exec(text)) !== null) {
        addFile(match[1], match[2].trim());
      }

      // 4. File: path \n ---- \n content \n ----
      const fileDashedRegex = /File:\s*(.*?)\s*\n----\n([\s\S]*?)\n----/g;
      while ((match = fileDashedRegex.exec(text)) !== null) {
        addFile(match[1], match[2]);
      }
    } catch (e) {
      console.error("Parse error:", e);
    }

    return extractedFiles;
  }, []);

  // Download function
  const downloadZip = useCallback(async (files) => {
    setStatus('downloading');
    setStatusMessage(`Packaging ${files.length} files into ZIP...`);

    try {
      const response = await axios.post(
        'http://localhost:5001/create-zip',
        { files },
        { responseType: 'blob' }
      );

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', 'project.zip');
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);

      setStatus('done');
      setStatusMessage(`✅ Downloaded project.zip with ${files.length} files!`);
    } catch (error) {
      console.error('Error downloading the zip file:', error);
      setStatus('error');
      setStatusMessage('❌ Failed to generate ZIP. Is the backend running?');
    }
  }, []);

  // Auto parse + auto download on text change (debounced)
  useEffect(() => {
    if (!inputText.trim()) {
      setStatus('idle');
      setStatusMessage('');
      setParsedCount(0);
      downloadTriggeredRef.current = false;
      return;
    }

    // Clear previous debounce
    if (debounceRef.current) clearTimeout(debounceRef.current);

    setStatus('parsing');
    setStatusMessage('Analyzing text...');

    // Wait 1.5s after user stops typing/pasting, then parse + download
    debounceRef.current = setTimeout(() => {
      const files = parseText(inputText);
      setParsedCount(files.length);

      if (files.length > 0) {
        setStatusMessage(`Found ${files.length} files. Generating ZIP...`);
        downloadZip(files);
      } else {
        setStatus('error');
        setStatusMessage('No files detected. Try pasting a Python dict, Markdown, or ==== delimited format.');
      }
    }, 1500);

    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
    };
  }, [inputText, parseText, downloadZip]);

  const statusColors = {
    idle: 'bg-gray-100 text-gray-500',
    parsing: 'bg-yellow-100 text-yellow-700',
    downloading: 'bg-blue-100 text-blue-700',
    done: 'bg-green-100 text-green-700',
    error: 'bg-red-100 text-red-700',
  };

  const statusIcons = {
    idle: '📋',
    parsing: '🔍',
    downloading: '📦',
    done: '✅',
    error: '⚠️',
  };

  return (
    <div className="max-w-3xl mx-auto p-6 bg-gray-50 min-h-screen flex flex-col">
      <div className="bg-white rounded-lg shadow-md p-8 flex flex-col flex-1">
        <h1 className="text-3xl font-bold mb-1 text-gray-800">
          Code → ZIP
        </h1>
        <p className="text-gray-500 mb-6 text-sm">
          Paste your code below. Files are auto-detected and downloaded as a ZIP — no buttons needed.
        </p>

        {/* Status Bar */}
        {statusMessage && (
          <div className={`mb-4 px-4 py-3 rounded-lg text-sm font-medium flex items-center gap-2 transition-all ${statusColors[status]}`}>
            <span className="text-lg">{statusIcons[status]}</span>
            <span>{statusMessage}</span>
            {status === 'parsing' && (
              <svg className="animate-spin h-4 w-4 ml-auto" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            )}
            {status === 'downloading' && (
              <svg className="animate-spin h-4 w-4 ml-auto" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            )}
          </div>
        )}

        <textarea
          value={inputText}
          onChange={(e) => setInputText(e.target.value)}
          className="w-full flex-1 min-h-[500px] p-4 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none font-mono text-sm bg-gray-50 resize-none"
          placeholder={`Just paste your code here and the ZIP downloads automatically!

Supported formats:

━━━ Python Dictionary ━━━
"src/App.js": """console.log('hello');"""

━━━ Markdown ━━━
**src/App.js**
\`\`\`javascript
console.log('hello');
\`\`\`

━━━ Delimiters ━━━
==== src/App.js ====
console.log('hello');`}
        />

        <p className="text-gray-400 text-xs mt-3 text-center">
          Paste text → files auto-detected → ZIP auto-downloads. That's it.
        </p>
      </div>
    </div>
  );
};

export default App;
